const { v4: uuidv4 } = require('uuid');
return [{
  json: {
    correlationId: uuidv4(),
    startedAt:     new Date().toISOString(),
    executionId:   $execution.id,
    workflowName:  'WF-11-prediction-accuracy-tracker',
  }
}];

const rows = $input.all();
const initData = $('Init').first().json;
if (rows.length === 0 || !rows[0].json.prediction_id) {
  return [{ json: { hasPending: false, ...initData } }];
}
return [{ json: { hasPending: true, pendingCount: rows.length, ...initData } }];

// ============================================================
// Calcula métricas de accuracy para uma previsão
// ============================================================
const p = $input.first().json;

const actualOutcome = p.actual_outcome; // 'home' | 'draw' | 'away'
if (!actualOutcome) {
  // Resultado ainda não determinável (ex: empate em fase sem empate)
  return [{ json: { skip: true, prediction_id: p.prediction_id } }];
}

// Outcome previsto = aquele com maior probabilidade
const probs = { home: p.home_win_prob, draw: p.draw_prob, away: p.away_win_prob };
const predictedOutcome = Object.entries(probs).reduce((a, b) => a[1] > b[1] ? a : b)[0];
const wasCorrect = predictedOutcome === actualOutcome;

// Brier Score: Σ(p_i - I_i)² para i ∈ {home, draw, away}
// I_i = 1 se outcome i ocorreu, 0 caso contrário
const I_home  = actualOutcome === 'home' ? 1 : 0;
const I_draw  = actualOutcome === 'draw' ? 1 : 0;
const I_away  = actualOutcome === 'away' ? 1 : 0;

const brierScore = parseFloat((
  Math.pow(p.home_win_prob - I_home, 2) +
  Math.pow(p.draw_prob    - I_draw,  2) +
  Math.pow(p.away_win_prob - I_away, 2)
).toFixed(4));

// Accuracy score contínuo: 1 - BS/2 (normaliza BS para [0,1])
// BS=0 → accuracy=1.0 (perfeito), BS=2 → accuracy=0.0 (pior possível)
const accuracyScore = parseFloat((1 - brierScore / 2).toFixed(2));

return [{
  json: {
    prediction_id:    p.prediction_id,
    match_id:         p.match_id,
    home_team_id:     p.home_team_id,
    away_team_id:     p.away_team_id,
    stage:            p.stage,
    match_date:       p.match_date,
    home_team_name:   p.home_team_name,
    away_team_name:   p.away_team_name,
    actual_outcome,
    actual_home:      p.actual_home,
    actual_away:      p.actual_away,
    predicted_outcome: predictedOutcome,
    was_correct:      wasCorrect,
    brier_score:      brierScore,
    accuracy_score:   accuracyScore,
    skip:             false,
  }
}];
